const item = $input.first().json;
const raw = (item.data?.text || item.output || item.text || item.content || item.response || JSON.stringify(item)).toString().trim();
const lower = raw.toLowerCase();

let decision;
let publish_at = '';

const okMatch = lower.match(/^(ok|tak|yes)(\s+(.+))?$/);
if (okMatch) {
  if (okMatch[3]) {
    const datePart = okMatch[3].trim();
    const m1 = datePart.match(/(\d{4})-(\d{2})-(\d{2})(?:\s+(\d{1,2}):(\d{2}))?/);
    const m2 = datePart.match(/(\d{1,2})[.](\d{1,2})[.](\d{4})(?:\s+(\d{1,2}):(\d{2}))?/);
    if (m1) {
      publish_at = m1[1] + '-' + m1[2] + '-' + m1[3];
      if (m1[4]) publish_at += ' ' + m1[4].padStart(2,'0') + ':' + (m1[5]||'00');
      decision = 'approve';
    } else if (m2) {
      publish_at = m2[3] + '-' + m2[2].padStart(2,'0') + '-' + m2[1].padStart(2,'0');
      if (m2[4]) publish_at += ' ' + m2[4].padStart(2,'0') + ':' + (m2[5]||'00');
      decision = 'approve';
    } else {
      decision = 'approve_no_date';
    }
  } else {
    decision = 'approve_no_date';
  }
} else if (['nie','no','odrzuc','odrzuć'].includes(lower)) {
  decision = 'reject';
} else {
  decision = 'revise';
}

const rowId = $('Get Jobs To Process').first().json._id;
const jobId = $('Get Jobs To Process').first().json.job_id;
const feedback = decision === 'revise' ? raw : '';
return [{ json: { decision, publish_at, row_id: rowId, job_id: jobId, revision_feedback: feedback } }];

const items = $('Generate Content').all();
if (!items.length) return [];
const rowId = $('Get Jobs To Process').first().json._id;
const slides = items.map(i => ({ channel: i.json.channel, body: i.json.generated_text }));
const generated_text = slides.map(s => '## ' + s.channel + '\n' + s.body).join('\n\n---\n\n');
return [{ json: { _id: rowId, generated_text, job_id: items[0].json.job_id } }];

return $('Generate Content').all().map(i => ({
  json: { job_id: i.json.job_id, channel: i.json.channel, generated_text: i.json.generated_text },
  binary: i.binary || {},
}));

const pr = $('Parse Response').first().json;
const publish_at = pr.publish_at || '';
return [{ json: { row_id: pr.row_id, job_id: pr.job_id, publish_at } }];

const ctx = $input.first().json;
return $('Generate Content').all().map(i => ({
  json: { ...i.json, row_id: ctx.row_id, job_id: ctx.job_id, publish_at: ctx.publish_at },
  binary: i.binary || {},
}));

const uploaded = $input.all();
const expanded = $('Expand for Drive Upload').all();
if (!uploaded.length || !expanded.length) return [];
const rowId = expanded[0].json.row_id;
const pub = expanded[0].json.publish_at;
const jobId = expanded[0].json.job_id;
const slides = uploaded.map((it, idx) => {
  const j = it.json;
  const ch = expanded[idx] && expanded[idx].json ? expanded[idx].json.channel : '';
  return {
    channel: ch,
    drive_file_id: j.id || j.fileId || '',
    drive_web_view_link: j.webViewLink || j.webContentLink || '',
  };
});
return [{ json: { row_id: rowId, publish_at: pub, final_slides: JSON.stringify(slides), job_id: jobId } }];

